Write-Host 'Installing Break Brush font...' -ForegroundColor Cyan
New-Item -ItemType Directory -Force -Path "public\fonts" | Out-Null
New-Item -ItemType Directory -Force -Path "src\styles" | Out-Null
[System.IO.File]::WriteAllBytes("public\fonts\BreakBrush.ttf", [System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllBytes("src\styles\globals.css", [System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllBytes("src\app\_sections\HeroSection.tsx", [System.Convert]::FromBase64String(""))
Write-Host 'Done! Check localhost:3000' -ForegroundColor Green